from .errors import DataBusError


class DataBus:
    """Core data bus for record processing."""

    RECORD_PREFIX = "rec_"

    def __init__(self):
        self._handlers = {}
        self._record_count = 0

    def subscribe(self, record_type, handler):
        """Register a handler for a record type."""
        if record_type not in self._handlers:
            self._handlers[record_type] = []
        self._handlers[record_type].append(handler)

    def process(self, record):
        """Process a record through all registered handlers."""
        record_type = record.get("type", "unknown")
        self._record_count += 1
        for handler in self._handlers.get(record_type, []):
            handler(record)

    def has_handlers(self, record_type):
        """Check if handlers exist for this type."""
        return len(self._handlers.get(record_type, [])) > 0

    def get_record_count(self):
        """Return total records processed."""
        return self._record_count

    def process_async(self, record):
        """Placeholder for async processing."""
        raise NotImplementedError("Use AsyncBus for async processing")

