from .core import DataBus


class LogBus(DataBus):
    """DataBus that logs all processed records."""

    def __init__(self):
        super().__init__()
        self.log = []

    def process(self, record):
        """Log record then delegate to parent."""
        self.log.append(record)
        super().process(record)

    def get_log_for_type(self, record_type):
        """Get logged records of a specific type."""
        return [r for r in self.log if r.get("type") == record_type]

