from .core import DataBus


class AsyncBus(DataBus):
    """DataBus that queues records for deferred processing."""

    def __init__(self):
        super().__init__()
        self._queue = []

    def process(self, record):
        """Queue record for later processing."""
        self._queue.append(record)

    def flush(self):
        """Process all queued records."""
        for record in self._queue:
            super().process(record)
        self._queue.clear()

    def pending_count(self):
        return len(self._queue)

