from .core import DataBus


class PriorityBus(DataBus):
    """DataBus that processes records by priority."""

    def __init__(self):
        super().__init__()
        self._pending = []

    def process(self, record):
        """Queue record with priority."""
        priority = record.get("priority", 0)
        self._pending.append((priority, record))

    def flush(self):
        """Process records highest priority first."""
        self._pending.sort(key=lambda x: -x[0])
        for _, record in self._pending:
            super().process(record)
        self._pending.clear()

