class BiDirectionalBus(DataBus):
    """DataBus that can process records in both directions."""

    def __init__(self):
        super().__init__()
        self._reverse_handlers = {}

    def subscribe_reverse(self, record_type, handler):
        """Register a reverse handler for a record type."""
        if record_type not in self._reverse_handlers:
            self._reverse_handlers[record_type] = []
        self._reverse_handlers[record_type].append(handler)

    def process(self, record):
        """Process record forward."""
        super().process(record)

    def process_reverse(self, record):
        """Process record through reverse handlers."""
        record_type = record.get("type", "unknown")
        for handler in self._reverse_handlers.get(record_type, []):
            handler(record)

