from .core import DataBus


class ChainBus(DataBus):
    """DataBus that chains multiple buses for sequential processing."""

    def __init__(self):
        super().__init__()
        self._chain = []

    def add_to_chain(self, bus):
        """Add a bus to the processing chain."""
        if not isinstance(bus, DataBus):
            raise TypeError(f"Expected DataBus, got {type(bus).__name__}")
        self._chain.append(bus)

    def process(self, record):
        """Process record through own handlers then chain."""
        super().process(record)
        for bus in self._chain:
            bus.process(record)

    def chain_length(self):
        return len(self._chain)

