from .core import DataBus
from .errors import ValidationError


class ValidatingBus(DataBus):
    """DataBus that validates records before processing."""

    def __init__(self, validators=None):
        super().__init__()
        self._validators = validators or []

    def add_validator(self, validator):
        """Add a validation function."""
        self._validators.append(validator)

    def process(self, record):
        """Validate record, then process."""
        for validator in self._validators:
            if not validator(record):
                raise ValidationError(f"Record failed validation: {record}")
        super().process(record)

