from .core import DataBus
from .filter_bus import FilterBus
from .log_bus import LogBus
from .async_bus import AsyncBus


class BusFactory:
    """Factory for creating DataBus instances."""

    @staticmethod
    def create(bus_type, **kwargs):
        """Create a DataBus instance by type name."""
        types = {
            "default": DataBus,
            "filter": FilterBus,
            "log": LogBus,
            "async": AsyncBus,
        }
        cls = types.get(bus_type)
        if cls is None:
            raise ValueError(f"Unknown bus type: {bus_type}")
        return cls(**kwargs)

    @staticmethod
    def create_default():
        """Create a plain DataBus."""
        return DataBus()

