from .core import DataBus


class BusRouter:
    """Routes records to appropriate DataBus instances."""

    def __init__(self):
        self._routes = {}

    def add_route(self, key, bus):
        """Add a routing rule."""
        if not isinstance(bus, DataBus):
            raise TypeError(f"Expected DataBus, got {type(bus).__name__}")
        self._routes[key] = bus

    def route(self, key, record):
        """Route a record to the appropriate bus."""
        bus = self._routes.get(key)
        if bus is None:
            raise KeyError(f"No route for key: {key}")
        bus.process(record)

    def broadcast(self, record):
        """Process record through all buses."""
        for bus in self._routes.values():
            bus.process(record)

    def route_count(self):
        return len(self._routes)
